/// Run oracle for a reduction that returns `IxDyn` (could be scalar or array).
/// The function takes `(array, Option<axis>)`.
pub fn run_reduction_f64_oracle<F>(path: &Path, func: F)
where
    F: Fn(&Array<f64, IxDyn>, Option<usize>) -> FerrayResult<Array<f64, IxDyn>>,
{
    let suite = load_fixture(path);
    let mut tested = 0;
    for case in &suite.test_cases {
        let input = &case.inputs["x"];
        if should_skip_f64(input) {
            continue;
        }
        let shape = parse_shape(&input["shape"]);
        if shape.is_empty() {
            continue;
        }
        let arr = make_f64_array(input);
        let axis = case
            .inputs
            .get("axis")
            .and_then(serde_json::Value::as_u64)
            .map(|v| v as usize);
        let result = func(&arr, axis)
            .unwrap_or_else(|e| panic!("case '{}': function returned error: {e}", case.name));
        let expected_data = parse_f64_data(&case.expected["data"]);
        let result_slice = result.as_slice().unwrap();
        assert_f64_slice_ulp(
            result_slice,
            &expected_data,
            case.tolerance_ulps.max(MIN_ULP_TOLERANCE),
            &case.name,
        );
        tested += 1;
    }
    assert!(tested > 0, "no f64 test cases found in {}", path.display());
}

/// Run oracle for a complex FFT: real input -> complex output.
pub fn run_real_to_complex_oracle<F>(path: &Path, func: F)
where
    F: Fn(&Array<f64, IxDyn>) -> FerrayResult<Array<Complex<f64>, IxDyn>>,
{
    let suite = load_fixture(path);
    let mut tested = 0;
    for case in &suite.test_cases {
        let input = &case.inputs["x"];
        let dtype = get_dtype(input);
        if dtype != "float64" {
            continue;
        }
        let shape = parse_shape(&input["shape"]);
        if shape.is_empty() {
            continue;
        }
        let arr = make_f64_array(input);
        let result = func(&arr)
            .unwrap_or_else(|e| panic!("case '{}': function returned error: {e}", case.name));
        let expected = parse_complex_data(&case.expected["data"]);
        let result_slice = result.as_slice().unwrap();
        assert_complex_slice_ulp(
            result_slice,
            &expected,
            case.tolerance_ulps.max(MIN_ULP_TOLERANCE),
            &case.name,
        );
        tested += 1;
    }
    // Previously this ran silently with zero test cases if a fixture
    // happened to have only complex inputs — so a missing dtype
    // handler or a broken fixture would produce a passing test
    // (#320). Match every other runner and require at least one case.
    assert!(
        tested > 0,
        "run_real_to_complex_oracle: no f64 cases were tested in {}",
        path.display()
    );
}

/// Run oracle for a complex->complex FFT.
pub fn run_complex_to_complex_oracle<F>(path: &Path, func: F)
where
    F: Fn(&Array<Complex<f64>, IxDyn>) -> FerrayResult<Array<Complex<f64>, IxDyn>>,
{
    let suite = load_fixture(path);
    let mut tested = 0;
    for case in &suite.test_cases {
        let input = &case.inputs["x"];
        let dtype = get_dtype(input);
        // Accept both real and complex inputs
        let arr = if dtype == "complex128" {
            make_complex_array(input)
        } else if dtype == "float64" {
            // Convert real to complex with zero imaginary
            let data = parse_f64_data(&input["data"]);
            let shape = parse_shape(&input["shape"]);
            let complex_data: Vec<Complex<f64>> =
                data.into_iter().map(|r| Complex::new(r, 0.0)).collect();
            Array::from_vec(IxDyn::new(&shape), complex_data).unwrap()
        } else {
            continue;
        };
        let shape = parse_shape(&input["shape"]);
        if shape.is_empty() {
            continue;
        }
        let result = func(&arr)
            .unwrap_or_else(|e| panic!("case '{}': function returned error: {e}", case.name));
        let expected = parse_complex_data(&case.expected["data"]);
        let result_slice = result.as_slice().unwrap();
        assert_complex_slice_ulp(
            result_slice,
            &expected,
            case.tolerance_ulps.max(MIN_ULP_TOLERANCE),
            &case.name,
        );
        tested += 1;
    }
    assert!(tested > 0, "no test cases found in {}", path.display());
}

